[CmdletBinding()]param([Parameter(Mandatory)][string]$Version,[string]$PrereleaseLabel='rc.1',[switch]$AllowUnsigned,[switch]$AllowDirtySource,[Parameter(Mandatory)][string]$SbomToolPath,[string]$ExpectedSbomToolVersion='4.1.5',[string]$ExpectedSbomToolSha256='',[string]$SignToolPath,[string]$CertificateThumbprint,[uri]$TimestampUrl,[string]$OutputRoot='.\artifacts\release')
$ErrorActionPreference='Stop';$repo=Split-Path $PSScriptRoot -Parent;if($Version-ne'1.0.0'){throw 'Version must match Directory.Build.props (1.0.0).'};if(-not$PrereleaseLabel-and$AllowUnsigned){throw 'Unsigned stable release rejected.'};$status=git -C $repo status --porcelain;if($status-and-not$AllowDirtySource){throw 'Release build requires a clean tracked working tree.'};& "$PSScriptRoot\Invoke-CI.ps1" -Configuration All -Platforms AnyCPU,x86,x64
& "$PSScriptRoot\Build-Installer.ps1";if($LASTEXITCODE){throw 'Installer build failed.'};$sourceSetup=Join-Path $repo 'artifacts\installer\LicenseScope-Setup.exe';$bundleName="LicenseScope-$Version-$PrereleaseLabel";if($AllowUnsigned){$bundleName+='-unsigned'};$bundle=Join-Path ([IO.Path]::GetFullPath((Join-Path $repo $OutputRoot))) $bundleName;New-Item -ItemType Directory -Force $bundle|Out-Null;Copy-Item $sourceSetup (Join-Path $bundle 'LicenseScope-Setup.exe') -Force
if(-not$AllowUnsigned){if(-not$SignToolPath-or-not$CertificateThumbprint-or-not$TimestampUrl){throw 'Stable/signed release requires signing inputs.'};& "$PSScriptRoot\Sign-ReleaseArtifacts.ps1" -SignToolPath $SignToolPath -CertificateThumbprint $CertificateThumbprint -TimestampUrl $TimestampUrl -InputPath (Join-Path $bundle 'LicenseScope-Setup.exe')}
$sbomWork=Join-Path (Split-Path $bundle) 'sbom-work';$sbom=& "$PSScriptRoot\Generate-Sbom.ps1" -SbomToolPath $SbomToolPath -DropPath $bundle -ComponentPath (Join-Path $repo 'src') -OutputDirectory $sbomWork -Version $Version -ExpectedVersion $ExpectedSbomToolVersion -ExpectedSha256 $ExpectedSbomToolSha256;Copy-Item $sbom (Join-Path $bundle "LicenseScope-$Version-sbom.spdx.json") -Force
$setup=Get-Item (Join-Path $bundle 'LicenseScope-Setup.exe');$sig=Get-AuthenticodeSignature $setup.FullName;$commit=(git -C $repo rev-parse HEAD).Trim();$manifest=[ordered]@{schemaVersion=1;product='LicenseScope';version=$Version;prerelease=$PrereleaseLabel;commit=$commit;setup=[ordered]@{file=$setup.Name;sizeBytes=$setup.Length;sha256=(Get-FileHash $setup.FullName -Algorithm SHA256).Hash;authenticode=$sig.Status.ToString();signer=if($sig.SignerCertificate){$sig.SignerCertificate.Subject}else{$null}};sbom=[ordered]@{file="LicenseScope-$Version-sbom.spdx.json";format='SPDX-2.2';sha256=(Get-FileHash (Join-Path $bundle "LicenseScope-$Version-sbom.spdx.json") -Algorithm SHA256).Hash};architecture=@('x86','x64');arm64='x86-emulated';generatedUtc=[DateTime]::UtcNow.ToString('o')};$manifest|ConvertTo-Json -Depth 6|Set-Content (Join-Path $bundle "LicenseScope-$Version-release-manifest.json") -Encoding UTF8
Copy-Item (Join-Path $repo "docs\release\RELEASE-NOTES-$Version-$PrereleaseLabel.md") (Join-Path $bundle 'RELEASE-NOTES.md');Copy-Item (Join-Path $repo 'docs\release\VERIFY.md') (Join-Path $bundle 'VERIFY.md');$hashFiles=@('LicenseScope-Setup.exe',"LicenseScope-$Version-sbom.spdx.json","LicenseScope-$Version-release-manifest.json",'RELEASE-NOTES.md','VERIFY.md');$hashFiles|ForEach-Object{"$((Get-FileHash (Join-Path $bundle $_) -Algorithm SHA256).Hash)  $_"}|Set-Content (Join-Path $bundle "LicenseScope-$Version-SHA256SUMS.txt") -Encoding ASCII;& "$PSScriptRoot\Verify-ReleaseBundle.ps1" -BundlePath $bundle -Version $Version -AllowUnsignedPrerelease:$AllowUnsigned;[pscustomobject]@{Status='PASS';Bundle=$bundle;SetupSha256=$manifest.setup.sha256;SbomSha256=$manifest.sbom.sha256;Authenticode=$manifest.setup.authenticode}
